export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:43。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨大到像是天在倒水。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館後方暫存區。應急照明燈投下一圈慘白的光，照著防護布蓋住的基座輪廓和幾個搬運用的金屬推車。光圈以外全是黑的。雨把所有的邊緣都打模糊了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個人已經到位。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠伏在暫存區外側的器材堆後面。相機鏡頭從兩個箱子之間的縫隙伸出來，對準基座底板的方向。她整個人被攝影背心和暗影吞掉，只剩鏡頭口反射著一點微光。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在後台側門的暗角裡。手裡握著一支小型 LED 燈，沒開，指腹按在開關上。他的任務只有一個——許星棠按下快門的那一刻，從另一個角度打光，讓底板上的東西無處可藏。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在暫存區與禮堂通道的交匯點。他的位置同時能看到校史館後門和通往禮堂的走廊。他靠著牆，帽衫的帽子拉到最低，手插在口袋裡，像是又一個躲雨的學生。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）21:45。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十七分鐘。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次，我不是一個人從門縫裡看。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次，我們三個人看。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:45。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監控切線開始了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有任何聲音提示。沒有警報，沒有閃燈。只是——顧言知道，從這一秒開始，到 22:02，校史館後方暫存區到禮堂後台之間的每一支攝像頭都在切換備援線路。十七分鐘的空白。和每一輪一模一樣。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）開始了。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:51。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館後門開了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是推開的。是用鑰匙開的。鑰匙轉動的聲音很輕，但在雨裡，金屬相碰的細響還是傳了過來。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任走出來。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他胸前別著行政組的證件。左手提著一個深色工具袋——不是展覽常用的那種白色搬運箱。是一個私人工具袋，拉鏈半開，裡面露出金屬邊角。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有打傘。雨水順著他的頭髮流下來，眼鏡片上全是水。他顧不上擦。他徑直走向基座，蹲下，掀開防護布的一角，露出底部的護板。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他真的來了。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）真的在監控空白裡。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）許星棠。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）拍。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的手指壓下快門。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有快門聲。雨太大了。但她知道畫面進去了——林主任蹲在基座旁邊，行政證件反著光，手伸向底板護板的螺絲。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任用工具袋裡的螺絲刀擰開護板。動作很快，很熟練。不像第一次。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "護板打開了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "底板下面是一個淺淺的夾層。林主任從裡面抽出——不是一疊完整的文件。是幾個薄的塑膠資料夾，一條金屬封條，和一個巴掌大的記憶卡盒。他把東西放進工具袋，然後從袋裡拿出另外幾個——尺寸相近，但明顯是空的替代品——塞回夾層。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "替換。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在換。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）把真的拿出來，把假的放回去。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十年前的東西——還在這裡。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠連續按了五下快門。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就是這一刻。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的 LED 燈亮了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白光從另一側打過來，精準地照在林主任的手上、底板的夾層上、工具袋裡露出的資料夾邊緣上。每一個細節都被釘在光裡。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任整個人凍住了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手還停在半空——一個塑膠資料夾夾在指縫裡，工具袋敞開著，替換品塞了一半。他的臉轉向光源，瞳孔在白光裡縮成針尖。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是一個人。是兩個方向。相機的鏡頭從左邊，燈光從右邊。他被夾在中間。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "——！", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他猛地站起來。膝蓋撞上基座邊角，工具袋翻倒，一個資料夾滑出來掉在積水的地上。他彎腰去撿——又停住——抬頭——左右看。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "誰——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從暗影裡走出來。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有跑。沒有喊。他只是走到了光圈的邊緣，站在林主任能看見的位置。雨打在他的帽衫上。他的表情很平。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "十七分鐘。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "——什麼？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "監控空白。十七分鐘。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不是系統故障。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "是你等著的時間。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的嘴唇在抖。他往後退了一步，背撞上基座。工具袋掉在地上的聲音被雨吞掉了一半。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "你——你怎麼在這裡——這是閉館區域，學生不能——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你在換什麼？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從器材堆後面站起來。相機沒有放下。鏡頭始終對著林主任。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "我——我在做撤展流程！基座護板要——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "撤展流程不需要私人工具袋。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "也不需要在監控切線的十七分鐘裡做。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從側門方向走過來。LED 燈沒關，光一直打著。他走到林主任的左後方，堵住了退向後台的路。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "底板裡的東西。拿出來看看。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "不是撤展。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "你們——你們是學生，你們無權——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "無權？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你能趁監控空白拆底板，我不能站在這裡看？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的嘴張了一下，沒有發出聲音。他的目光在三個人之間跳——左邊的相機，右邊的燈，正面的顧言。他被三角包圍了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "十年前。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "南翼整修的工程資料。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "是你改的紀錄。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的臉完全白了。不是生氣的白。是那種血全部從臉上抽走、只剩下一層蠟的白。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "你們——你們根本不知道——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "你們不知道那東西牽扯到誰——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音突然拔高，又被一陣灌進暫存區的風壓了下去。暴雨砸在金屬推車上，發出密集的鼓點。禮堂方向隱約傳來閉幕排練的廣播回聲。所有的聲音疊在一起，把林主任的話撕成碎片。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "牽扯到誰？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你說。牽扯到誰？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "我——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他吞了一下口水。喉結上下滾了一下。他的手在抖，抖得很厲害，眼鏡從鼻樑上滑下來他也沒推。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "我只是⋯⋯照當年的流程⋯⋯補紀錄⋯⋯", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "那份資料本來就⋯⋯就不該留在基座裡⋯⋯", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不該留在基座裡。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "那它應該留在哪裡？被你拿走？被你燒掉？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "不是——不是你們想的那樣——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "我沒有——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的聲音又斷了。推車被風推動，發出一聲尖銳的金屬摩擦。廣播的回聲突然變大又變小，像有人在調音量。林主任的嘴還在動，但只有一半的音節穿過雨聲傳到顧言耳朵裡。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "⋯⋯照安排做的⋯⋯不是我決定⋯⋯", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "⋯⋯你們不知道那牽扯到⋯⋯", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「照安排做的。」", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是「照我說的做」。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是「照安排做的」。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯照安排做的。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）誰的安排？", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在害怕。不是被抓的害怕。是那種——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——那種怕被背後那個人發現的感覺。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這個念頭只閃了一下，就被另一個更大的念頭蓋過去了。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不管背後是誰。他動了底板。他換了東西。這就夠了。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次，有照片。有目擊。有三個人。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次不是門縫裡的影子。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠低頭看了一眼相機螢幕。照片在。每一張都在。林主任的臉、手、工具袋、底板夾層、替換品。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "照片拍到了。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "韓越，側門確認沒有別人進出。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "只有他。從後門進，沒有第二個人。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "好。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抬起頭，看向林主任。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "林主任。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你現在跟我們走。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "去——去哪——", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "人多的地方。", background: Background.Chapter_6_Ch6_Act10_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。十七分鐘的空白正在一秒一秒地流走。林主任站在原地，像一棵被風吹斷了根的樹，搖搖晃晃，不知道該倒向哪邊。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他手裡還攥著工具袋。底板護板敞著。假的替代品歪歪斜斜地塞在夾層裡。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "真的東西在他的袋子裡。也在許星棠的照片裡。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:02。", background: Background.Chapter_6_Ch6_Act10_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十七分鐘結束了。", background: Background.Chapter_6_Ch6_Act10_S0 },
];
